#!/usr/bin/env python
"""
MABE Bootstrap: Fragment Library Expansion
==========================================
Expands de novo generation fragment libraries:
  14 new backbones (crown ethers, cryptand, terpyridine, phenanthroline,
    triazine, bipyrazole, peptidic scaffolds, BPA, IDA, DTPA)
  16 new arms (peptidic side chains, boronic acids, anion recognition,
    ether donors, NHC, isocyanide, tetrazolyl, pyrazolyl)
  6 new bioisostere groups (boronic_acid, anion_donor, mono_O_ether,
    mono_C_soft, peptidic_multi) + existing groups updated

Library: 28→42 backbones, 35→51 arms, 10→15 bioisostere groups

Supersedes: bootstrap_novel_host_gen.py (includes all prior patches)
Requires: bootstrap_novel_materials.py applied first

Usage:
  python bootstrap_fragment_expansion.py
  python -m pytest tests/test_fragment_expansion.py tests/test_de_novo_generator.py -v

Expected: 245 passed (168 + 77), 0 failed
"""
import base64, os, sys, shutil

def write_b64(path, data_b64):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(data_b64))
    print(f"  Written: {path} ({os.path.getsize(path)} bytes)")

def main():
    root = os.path.dirname(os.path.abspath(__file__))
    if not os.path.isfile(os.path.join(root, "core", "universal_schema.py")):
        root = os.path.dirname(root)
    if not os.path.isfile(os.path.join(root, "core", "universal_schema.py")):
        print("ERROR: Run from MABE repo root.")
        sys.exit(1)

    print("MABE Bootstrap: Fragment Library Expansion")
    print("=" * 50)

    dng = os.path.join(root, "core", "de_novo_generator.py")
    bak = dng + ".pre_fragment_expansion.bak"
    if not os.path.isfile(bak):
        shutil.copy2(dng, bak)
        print(f"  Backup: {bak}")

    write_b64(os.path.join(root, "core/de_novo_generator.py"), "")
    write_b64(os.path.join(root, "tests/test_fragment_expansion.py"), "")

    print()
    print("Validation:")
    print("  python -m pytest tests/test_fragment_expansion.py tests/test_de_novo_generator.py -v")
    print()
    print("Expected: 245 passed (168 fragment + 77 de novo), 0 failed")

if __name__ == "__main__":
    main()